      stream.next(m.output_tracking_error);
      stream.next(m.gps_check_fail_flags);
      stream.next(m.control_mode_flags);
      stream.next(m.filter_fault_flags);
      stream.next(m.pos_horiz_accuracy);
      stream.next(m.pos_vert_accuracy);
